import subprocess
import os
import sys

def convertDocument(input_file, output_file, format_type):
    # Validate input file exists
    if not os.path.exists(input_file):
        raise FileNotFoundError(f"Input file {input_file} not found")
    
    # Validate format_type is in allowed list
    allowed_formats = ['pdf', 'docx', 'odt', 'txt', 'html', 'jpg', 'png', 'bmp']
    if format_type.lower() not in allowed_formats:
        raise ValueError(f"Unsupported format: {format_type}")
    
    # Build output file path with correct extension
    output_extension = format_type.lower()
    if not output_file.endswith(f".{output_extension}"):
        output_file = f"{output_file}.{output_extension}"
    
    # Ensure output directory exists
    output_dir = os.path.dirname(output_file) or '.'
    os.makedirs(output_dir, exist_ok=True)
    
    # Use LibreOffice in headless mode for conversion
    try:
        # Use subprocess with list of arguments to avoid shell injection
        cmd = [
            'libreoffice',
            '--headless',
            '--convert-to',
            format_type,
            '--outdir',
            output_dir,
            input_file
        ]
        
        # Execute the command
        result = subprocess.run(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            check=True,
            text=True
        )
        
        # Return the path to the converted file
        return output_file
        
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Conversion failed: {e.stderr}")
    except FileNotFoundError:
        raise RuntimeError("LibreOffice not found. Please install LibreOffice.")

